import { createRouter, createWebHistory } from 'vue-router'
import type { RouteRecordRaw } from 'vue-router'
import { authRoutes } from './routers/auth'
import { createRoutes } from "./routers/create"
import { userRoutes } from './routers/user'
import { homeRoutes } from './routers/home'
import { galleryRoutes } from './routers/gallery'
import { detailRoutes } from "./routers/workDetail"
import { entryRoutes } from './routers/entry'
import { publishReadyRouters } from './routers/publishReady'

// import { billingRoutes } from './routes/billing'
// import { systemRoutes } from './routes/system'

const routes: RouteRecordRaw[] = [
  ...authRoutes,
  ...createRoutes,
  ...userRoutes,
  ...homeRoutes,
  ...galleryRoutes,
  ...detailRoutes,
  ...entryRoutes,
  ...publishReadyRouters
]

export const router = createRouter({
  history: createWebHistory(),
  routes,
})
